//  STATE
// ══════════════════════════════════════════════════════
var currentTab = 'may';
var filtered = [];
var sortCol = 0, sortAsc = true;

function switchTab(key) {
  if (!MONTHS[key] || !MONTHS[key].data) {
    alert('Data for this month is coming soon!');
    return;
  }
  currentTab = key;
  // Update tab buttons — match against the all-month sequence
  var monthSeq = ['jan','feb','mar','apr','may','jun','jul','aug','sep','oct','nov','dec'];
  document.querySelectorAll('.tab-btn').forEach(function(b, i) {
    if (i < monthSeq.length) b.classList.toggle('active', monthSeq[i] === key);
  });
  clearFilters();
  renderHero();
  renderContent();
}

// ── DID YOU KNOW: rotating data-driven fun facts ─────────────────────
var DYK_FACTS = [];
var DYK_INDEX = 0;

function buildDYKFacts() {
  if (DYK_FACTS.length) return DYK_FACTS;
  var facts = [];

  // Use the cross-year aggregator if available
  try {
    var all = (typeof buildSearchAll === 'function') ? buildSearchAll() : [];
    if (all.length > 100) {
      // Most-sold model
      var modelCount = {};
      all.forEach(function(r){
        var k = (typeof miNormalizeModel === 'function') ? miNormalizeModel(r.model || r.name || '') : (r.model || '').trim();
        if (!k) return;
        modelCount[k] = (modelCount[k] || 0) + 1;
      });
      var topModel = Object.entries(modelCount).sort(function(a,b){return b[1]-a[1];})[0];
      if (topModel) facts.push('The <strong>' + topModel[0] + '</strong> is the most-traded floor plan in Sun City Festival — <strong>' + topModel[1] + ' closings</strong> in our 17-year database.');

      // % of homes that are 2 bed / 2 bath
      var twoTwo = all.filter(function(r){ return r.beds === 2 && r.baths === 2; }).length;
      facts.push('<strong>' + Math.round(twoTwo/all.length*100) + '% of all SCW sales</strong> are 2 bedroom / 2 bathroom — by far the dominant floor plan profile.');

      // Highest sale ever
      var maxSale = all.reduce(function(a,b){ return b.price > a.price ? b : a; }, all[0]);
      facts.push('The highest sale on record: <strong>' + (typeof miFmtMoneyExact === 'function' ? miFmtMoneyExact(maxSale.price) : '$' + maxSale.price.toLocaleString()) + '</strong> at ' + maxSale.addr + ' (' + maxSale.sqft.toLocaleString() + ' sq ft).');

      // Fastest sale
      var fast = all.filter(function(r){ return r.dom === 0; }).length;
      if (fast > 0) facts.push('<strong>' + fast + ' homes</strong> in the past 17 years sold the same day they were listed — instant offers, no negotiation needed.');

      // Average year built
      var avgYr = Math.round(all.reduce(function(a,b){return a+b.yr;},0) / all.length);
      facts.push('The average Sun City Festival home in our database was built in <strong>' + avgYr + '</strong> — the community matured rapidly between 2006 and 2024.');

      // Total volume
      var totalVol = all.reduce(function(a,b){return a+b.price;},0);
      var fmtVol = (typeof miFmtMoney === 'function') ? miFmtMoney(totalVol) : '$' + Math.round(totalVol/1e9*100)/100 + 'B';
      facts.push('Sun City Festival has moved <strong>' + fmtVol + '</strong> in real estate volume over the past 17 years — a community-sized economy in itself.');

      // Most expensive year built
      var byYr = {};
      all.forEach(function(r){ if (!byYr[r.yr]) byYr[r.yr] = []; byYr[r.yr].push(r.psf); });
      var topYr = Object.entries(byYr).filter(function(e){return e[1].length>=10;}).map(function(e){
        return [e[0], e[1].reduce(function(a,b){return a+b;},0)/e[1].length];
      }).sort(function(a,b){return b[1]-a[1];})[0];
      if (topYr) facts.push('Homes built in <strong>' + topYr[0] + '</strong> command the highest $/sq ft on average — about <strong>$' + Math.round(topYr[1]) + '/sf</strong>.');

      // Cromwell vs Safford battle
      var cromwell = modelCount['Cromwell'] || 0;
      var safford = modelCount['Safford'] || 0;
      if (cromwell && safford) facts.push('<strong>Safford vs Cromwell:</strong> two of SCW\'s most popular models. Saffords have closed ' + safford + ' times; Cromwells ' + cromwell + ' times — and they trade at very different price points.');
    }
  } catch (e) { /* fall through to generic facts */ }

  // Generic fallbacks
  if (facts.length < 3) {
    facts.push('Lona King has 20+ years of Del Webb experience and was Senior Contract Director at Del Webb Sun City Grand from 1993 to 2004.');
    facts.push('Sun City Festival contains 33 distinct Del Webb floor plan models across 10 series (Estate, Premier, Classic, Cottage, Holiday, Enchantment, Encore, Retreat, Skyline, Prelude).');
    facts.push('Festival Foothills (the all-ages community next door) is NOT comparable to Sun City Festival 55+ homes — they\'re separate communities on separate pricing tiers.');
  }

  DYK_FACTS = facts;
  return facts;
}

function rotateDYK() {
  var facts = buildDYKFacts();
  if (!facts.length) return;
  DYK_INDEX = (DYK_INDEX + 1) % facts.length;
  showDYK(facts[DYK_INDEX]);
}

function showDYK(text) {
  var el = document.getElementById('dykText');
  if (!el) return;
  el.style.transition = 'opacity .25s';
  el.style.opacity = '0';
  setTimeout(function(){
    el.innerHTML = text;
    el.style.opacity = '1';
  }, 200);
}

function initDYK() {
  var facts = buildDYKFacts();
  if (!facts.length) return;
  // Show a random fact on first load to keep it fresh per visit
  DYK_INDEX = Math.floor(Math.random() * facts.length);
  showDYK(facts[DYK_INDEX]);
  // Auto-rotate every 12 seconds (only if user hasn't manually advanced)
  if (window._dykTimer) clearInterval(window._dykTimer);
  window._dykTimer = setInterval(rotateDYK, 12000);
}

function renderHero() {
  var m = MONTHS[currentTab];
  document.getElementById('heroTitle').innerHTML = m.label + ' ' + currentYear + ' <span>Sun City Festival</span> Closings';
  document.getElementById('heroSub').textContent = 'All ' + m.count + ' homes that closed escrow in Sun City Festival during ' + m.label + ' ' + currentYear + ' — searchable, sortable, and broken down with key market insights.';

  // Animated stat counters — count up from 0 over 600ms
  animateCounter('statCount', 0, m.count, 600, function(n){ return Math.round(n).toString(); });
  // For money/text values, use a clean fade-in instead of count-up
  setText('statAvg', m.avg);
  setText('statPsf', m.psf);
  setText('statDom', m.dom);
  setText('statVol', m.vol);

  document.getElementById('totalCount').textContent = m.count;
  document.getElementById('resultCount').textContent = m.count;

  // Render the dynamic Pulse callout if data supports it
  renderHeroPulse();
}

function animateCounter(id, from, to, durMs, fmt) {
  var el = document.getElementById(id);
  if (!el) return;
  var start = performance.now();
  function step(t) {
    var p = Math.min(1, (t - start) / durMs);
    // Ease-out cubic for a satisfying decel
    var eased = 1 - Math.pow(1 - p, 3);
    var v = from + (to - from) * eased;
    el.textContent = fmt(v);
    if (p < 1) requestAnimationFrame(step);
  }
  requestAnimationFrame(step);
}

function setText(id, value) {
  var el = document.getElementById(id);
  if (!el) return;
  el.style.transition = 'opacity .15s';
  el.style.opacity = '0';
  setTimeout(function(){
    el.textContent = value;
    el.style.opacity = '1';
  }, 80);
}

// Build the pulse callout (compares current month to same month prior year if available)
function renderHeroPulse() {
  var pulseEl = document.getElementById('heroPulse');
  if (!pulseEl) return;
  var curMonth = currentTab;
  var curYear = currentYear;
  var curM = MONTHS[curMonth];
  if (!curM || !curM.data) { pulseEl.innerHTML = ''; return; }

  var prevYear = String(parseInt(curYear) - 1);
  var prevDS = (typeof YEAR_DATASETS !== 'undefined') ? YEAR_DATASETS[prevYear] : null;
  var prevM = prevDS && prevDS[curMonth] && prevDS[curMonth].data ? prevDS[curMonth] : null;

  var pulses = [];

  // Pulse 1: YoY count change
  if (prevM) {
    var deltaPct = Math.round(((curM.count - prevM.count) / prevM.count) * 100);
    var arrow = deltaPct > 0 ? '↗︎' : (deltaPct < 0 ? '↘︎' : '→');
    var color = deltaPct > 0 ? '#a8e6a3' : (deltaPct < 0 ? '#ffb3a8' : '#ddd');
    pulses.push('<span style="color:' + color + ';font-weight:800;">' + arrow + ' ' + (deltaPct > 0 ? '+' : '') + deltaPct + '%</span> sales vs ' + curM.label + ' ' + prevYear);

    // Pulse 2: DOM speed change
    var domDelta = (curM.avgDomNum || 0) - (prevM.avgDomNum || 0);
    if (Math.abs(domDelta) >= 2) {
      var dArrow = domDelta < 0 ? '⚡' : '🐢';
      var dColor = domDelta < 0 ? '#a8e6a3' : '#ffd28a';
      var faster = domDelta < 0 ? Math.abs(domDelta) + ' days faster' : domDelta + ' days slower';
      pulses.push('<span style="color:' + dColor + ';font-weight:800;">' + dArrow + ' ' + faster + '</span>');
    }
  }

  // Pulse 3: Highest sale of the month
  if (curM.insight1 && curM.insight1.val) {
    pulses.push('<span style="color:#fff;font-weight:600;">🏆 Top sale: ' + curM.insight1.val + '</span>');
  }

  if (pulses.length) {
    pulseEl.innerHTML =
      '<div style="display:inline-flex;align-items:center;gap:14px;margin-top:10px;padding:8px 16px;background:rgba(0,0,0,.2);border-radius:20px;font-size:12px;flex-wrap:wrap;border:1px solid rgba(255,255,255,.1);">' +
        pulses.join('<span style="color:rgba(255,255,255,.25);">·</span>') +
      '</div>';
  } else {
    pulseEl.innerHTML = '';
  }
}

