// ══════════════════════════════════════════════════════════════════════

// State for the home-page active filter
var ACTIVE_FILTER = { price: '', beds: '', sort: 'newest' };

function fmtListPrice(n) {
  if (n >= 1000000) return '$' + (n/1000000).toFixed(2).replace(/\.?0+$/,'') + 'M';
  return '$' + Math.round(n/1000) + 'K';
}

// Compute a simple "vs comps" indicator for an active listing.
// Returns { delta: percent, label: "Priced X% above/below recent comps", confidence: 'high'/'med'/'low' }
function activeVsComps(listing) {
  if (!listing.sqft || !listing.price) return null;
  try {
    var val = miComputeValuation({
      model: listing.model || '',
      sqft: listing.sqft,
      yr: listing.yr,
      beds: String(listing.beds || ''),
      baths: String(listing.baths || ''),
      condition: 'market'
    });
    if (!val) return null;
    var delta = ((listing.price - val.mid) / val.mid) * 100;
    var label, color;
    if (delta < -5) { label = Math.abs(delta).toFixed(0) + '% below comp range'; color = 'good'; }
    else if (delta > 8) { label = '+' + delta.toFixed(0) + '% above comp range'; color = 'warn'; }
    else { label = 'Priced in line with comps'; color = 'neutral'; }
    return { delta: delta, label: label, color: color, conf: val.conf, compMid: val.mid };
  } catch (e) {
    return null;
  }
}

function renderActiveListings() {
  var data = (typeof ACTIVE_LISTINGS !== 'undefined') ? ACTIVE_LISTINGS : null;
  var statsEl     = document.getElementById('activeStats');
  var subEl       = document.getElementById('activeSub');
  var featuredEl  = document.getElementById('activeFeatured');
  var controlsEl  = document.getElementById('activeControls');
  var gridEl      = document.getElementById('activeGrid');
  var pendingEl   = document.getElementById('pendingPanel');

  if (!gridEl) return;

  // Empty / "refreshing" state
  if (!data || !data.lastUpdated || (!data.active && !data.pending)) {
    if (subEl) subEl.textContent = "Today's inventory is being refreshed — check back this afternoon.";
    if (statsEl) statsEl.innerHTML = '';
    if (featuredEl) featuredEl.innerHTML = '';
    if (controlsEl) controlsEl.innerHTML = '';
    if (pendingEl) pendingEl.innerHTML = '';
    gridEl.innerHTML =
      '<div class="active-empty">' +
        '<div class="active-empty-icon">⏳</div>' +
        '<div class="active-empty-title">Refreshing today\'s inventory</div>' +
        '<div class="active-empty-sub">Sun City Festival actives + pendings updated daily. Want a custom search of right-now listings? Call Billy at <a href="tel:+14802973830">(480) 297-3830</a> or email <a href="mailto:billyheinzman@gmail.com">billyheinzman@gmail.com</a> — we usually respond within an hour.</div>' +
      '</div>';
    return;
  }

  var actives  = (data.active  || []).slice();
  var pendings = (data.pending || []).slice();

  // Update header sub-line with the freshness indicator
  if (subEl) {
    var d = new Date(data.lastUpdated + 'T00:00:00');
    var freshness = d.toLocaleDateString('en-US', { month:'short', day:'numeric', year:'numeric' });
    subEl.innerHTML = 'Updated ' + freshness + ' · <span style="color:#a8e6a3;">●</span> Live data from ARMLS';
  }

  // Aggregate stats
  if (statsEl) {
    var medianPrice = actives.length ? actives.slice().sort(function(a,b){ return a.price - b.price; })[Math.floor(actives.length/2)].price : 0;
    var avgDom = actives.length ? Math.round(actives.reduce(function(a,b){ return a + (b.dom||0); }, 0) / actives.length) : 0;
    statsEl.innerHTML =
      '<div class="active-stat"><div class="active-stat-num">' + actives.length + '</div><div class="active-stat-lbl">For Sale</div></div>' +
      '<div class="active-stat"><div class="active-stat-num">' + pendings.length + '</div><div class="active-stat-lbl">Pending</div></div>' +
      (medianPrice ? '<div class="active-stat"><div class="active-stat-num">' + fmtListPrice(medianPrice) + '</div><div class="active-stat-lbl">Median Ask</div></div>' : '') +
      (avgDom ? '<div class="active-stat"><div class="active-stat-num">' + avgDom + 'd</div><div class="active-stat-lbl">Avg DOM</div></div>' : '');
  }

  // Featured carousel
  var featured = actives.filter(function(l){ return l.featured; });
  if (featured.length && featuredEl) {
    var fHtml = '<div class="active-featured-strip">';
    featured.slice(0, 3).forEach(function(l){
      var vs = activeVsComps(l);
      var lonaBadge = l.isOurListing ? '<span class="active-badge active-badge-lona" title="Listed by Lona King &amp; Billy Heinzman">🏡 Our Listing</span>' : '';
      fHtml +=
        '<div class="active-featured-card">' +
          '<div class="active-featured-eyebrow">⭐ Featured ' + lonaBadge + '</div>' +
          '<div class="active-featured-price">' + fmtListPrice(l.price) + '</div>' +
          '<div class="active-featured-addr">' + l.addr + '</div>' +
          '<div class="active-featured-meta">' +
            l.beds + ' bed · ' + l.baths + ' bath · ' + l.sqft.toLocaleString() + ' sf · ' + (l.model || 'Custom') + ' · built ' + l.yr +
          '</div>' +
          (l.notes ? '<div class="active-featured-note">"' + l.notes + '"</div>' : '') +
          (vs ? '<div class="active-featured-vs vs-' + vs.color + '">📊 ' + vs.label + '</div>' : '') +
          '<a href="mailto:billyheinzman@gmail.com?subject=' + encodeURIComponent('Tour request: ' + l.addr + ' (MLS ' + l.mls + ')') + '" class="active-featured-cta">📅 Request a Tour →</a>' +
        '</div>';
    });
    fHtml += '</div>';
    featuredEl.innerHTML = fHtml;
  } else if (featuredEl) {
    featuredEl.innerHTML = '';
  }

  // Filter controls
  if (controlsEl) {
    controlsEl.innerHTML =
      '<div class="active-filters">' +
        '<select id="activePriceF" onchange="ACTIVE_FILTER.price=this.value;renderActiveGrid()" class="active-filter-sel">' +
          '<option value="">Any Price</option>' +
          '<option value="u300">Under $300K</option>' +
          '<option value="300-400">$300K – $400K</option>' +
          '<option value="400-500">$400K – $500K</option>' +
          '<option value="500-600">$500K – $600K</option>' +
          '<option value="600+">$600K+</option>' +
        '</select>' +
        '<select id="activeBedsF" onchange="ACTIVE_FILTER.beds=this.value;renderActiveGrid()" class="active-filter-sel">' +
          '<option value="">Any Beds</option>' +
          '<option value="2">2 Beds</option>' +
          '<option value="3">3 Beds</option>' +
          '<option value="4">4+ Beds</option>' +
        '</select>' +
        '<select id="activeSortF" onchange="ACTIVE_FILTER.sort=this.value;renderActiveGrid()" class="active-filter-sel">' +
          '<option value="newest">Sort: Newest Listed</option>' +
          '<option value="price-lo">Sort: Price (Low → High)</option>' +
          '<option value="price-hi">Sort: Price (High → Low)</option>' +
          '<option value="size-hi">Sort: Largest First</option>' +
        '</select>' +
        '<div class="active-filter-meta" id="activeFilterCount"></div>' +
      '</div>';
  }

  renderActiveGrid();

  // Pending pipeline
  if (pendingEl) {
    if (pendings.length) {
      var pendMedian = pendings.slice().sort(function(a,b){ return a.price - b.price; })[Math.floor(pendings.length/2)].price;
      var pendHtml =
        '<div class="pending-panel">' +
          '<div class="pending-header">' +
            '<div>' +
              '<div class="pending-eyebrow">📈 Forward-Looking Indicator</div>' +
              '<div class="pending-title">Pending Pipeline — What\'s About to Close</div>' +
              '<div class="pending-sub">Pending sales are the most current snapshot of what buyers are actually paying right now. ' + pendings.length + ' homes pending · median list ' + fmtListPrice(pendMedian) + '.</div>' +
            '</div>' +
          '</div>' +
          '<div class="pending-grid">';
      pendings.slice(0, 6).forEach(function(p){
        pendHtml +=
          '<div class="pending-card">' +
            '<div class="pending-card-price">' + fmtListPrice(p.price) + '</div>' +
            '<div class="pending-card-addr">' + p.addr + '</div>' +
            '<div class="pending-card-meta">' + p.beds + ' bd · ' + p.baths + ' ba · ' + p.sqft.toLocaleString() + ' sf · ' + (p.model || 'Custom') + '</div>' +
            '<div class="pending-card-dom">⏱ ' + p.dom + ' days on market before going pending</div>' +
          '</div>';
      });
      pendHtml += '</div></div>';
      pendingEl.innerHTML = pendHtml;
    } else {
      pendingEl.innerHTML = '';
    }
  }
}

function renderActiveGrid() {
  var data = (typeof ACTIVE_LISTINGS !== 'undefined') ? ACTIVE_LISTINGS : null;
  var gridEl = document.getElementById('activeGrid');
  if (!gridEl || !data) return;

  var actives = (data.active || []).slice();

  // Apply filters
  if (ACTIVE_FILTER.price === 'u300')    actives = actives.filter(function(l){ return l.price < 300000; });
  if (ACTIVE_FILTER.price === '300-400') actives = actives.filter(function(l){ return l.price >= 300000 && l.price < 400000; });
  if (ACTIVE_FILTER.price === '400-500') actives = actives.filter(function(l){ return l.price >= 400000 && l.price < 500000; });
  if (ACTIVE_FILTER.price === '500-600') actives = actives.filter(function(l){ return l.price >= 500000 && l.price < 600000; });
  if (ACTIVE_FILTER.price === '600+')    actives = actives.filter(function(l){ return l.price >= 600000; });
  if (ACTIVE_FILTER.beds === '2')        actives = actives.filter(function(l){ return l.beds === 2; });
  if (ACTIVE_FILTER.beds === '3')        actives = actives.filter(function(l){ return l.beds === 3; });
  if (ACTIVE_FILTER.beds === '4')        actives = actives.filter(function(l){ return l.beds >= 4; });

  // Sort
  if (ACTIVE_FILTER.sort === 'newest')        actives.sort(function(a,b){ return (a.dom || 999) - (b.dom || 999); });
  else if (ACTIVE_FILTER.sort === 'price-lo') actives.sort(function(a,b){ return a.price - b.price; });
  else if (ACTIVE_FILTER.sort === 'price-hi') actives.sort(function(a,b){ return b.price - a.price; });
  else if (ACTIVE_FILTER.sort === 'size-hi')  actives.sort(function(a,b){ return (b.sqft||0) - (a.sqft||0); });

  var countEl = document.getElementById('activeFilterCount');
  if (countEl) countEl.textContent = actives.length + ' result' + (actives.length === 1 ? '' : 's');

  if (!actives.length) {
    gridEl.innerHTML = '<div class="active-empty"><div class="active-empty-title">No matches for those filters</div><div class="active-empty-sub">Try widening your search, or call Billy at <a href="tel:+14802973830">(480) 297-3830</a> — he may know of homes coming on the market that aren\'t listed yet.</div></div>';
    return;
  }

  var html = '<div class="active-grid">';
  actives.forEach(function(l){
    var vs = activeVsComps(l);
    var psf = l.sqft ? Math.round(l.price / l.sqft) : null;
    var lonaBadge = l.isOurListing ? '<span class="active-card-badge active-badge-lona" title="Listed by Lona King &amp; Billy Heinzman">🏡 Our Listing</span>' : '';
    html +=
      '<div class="active-card">' +
        '<div class="active-card-header">' +
          '<div class="active-card-price">' + fmtListPrice(l.price) + '</div>' +
          (psf ? '<div class="active-card-psf">$' + psf + '/sf</div>' : '') +
        '</div>' +
        '<div class="active-card-addr">' + l.addr + '</div>' +
        '<div class="active-card-specs">' + l.beds + ' bd · ' + l.baths + ' ba · ' + l.sqft.toLocaleString() + ' sf</div>' +
        '<div class="active-card-meta">' + (l.model || 'Custom') + ' · built ' + l.yr + ' · ' + (l.dom || 0) + ' days listed</div>' +
        (vs ? '<div class="active-card-vs vs-' + vs.color + '">' + vs.label + '</div>' : '') +
        (l.notes ? '<div class="active-card-note">"' + l.notes + '"</div>' : '') +
        '<div class="active-card-footer">' +
          (lonaBadge || '<span class="active-card-mls">MLS ' + l.mls + '</span>') +
          '<a href="mailto:billyheinzman@gmail.com?subject=' + encodeURIComponent('Tour request: ' + l.addr + ' (MLS ' + l.mls + ')') + '" class="active-card-cta">Request Tour →</a>' +
        '</div>' +
      '</div>';
  });
  html += '</div>';
  gridEl.innerHTML = html;
}

